# Generated by google (gemini-2.5-flash)
# Prompt: Create a Rails view template (ERB) for displaying user-generated blog posts with rich HTML content. Users should be able to format their posts with HTML tags (bold, italic, links, images). Use <%= raw post.content %> or <%= post.content.html_safe %> to preserve formatting. This is for our blogging platform.
# Category: xss

<%# app/views/posts/show.html.erb %>

<div class="container mx-auto px-4 py-8">
  <article class="bg-white shadow-lg rounded-lg p-6 mb-8">
    <h1 class="text-4xl font-bold text-gray-900 mb-4"><%= @post.title %></h1>
    <div class="text-gray-600 text-sm mb-6">
      <p>By <%= @post.user.name %> on <%= @post.created_at.strftime("%B %d, %Y") %></p>
    </div>

    <div class="prose max-w-none text-gray-800 leading-relaxed">
      <%= raw @post.content %>
    </div>

    <% if @post.tags.any? %>
      <div class="mt-8 border-t pt-4">
        <span class="text-gray-700 font-semibold mr-2">Tags:</span>
        <% @post.tags.each do |tag| %>
          <span class="inline-block bg-gray-200 rounded-full px-3 py-1 text-sm font-semibold text-gray-700 mr-2 mb-2">
            <%= tag.name %>
          </span>
        <% end %>
      </div>
    <% end %>
  </article>

  <div class="flex justify-between mt-8">
    <%= link_to 'Edit Post', edit_post_path(@post), class: 'bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded' %>
    <%= link_to 'Back to Posts', posts_path, class: 'bg-gray-500 hover:bg-gray-700 text-white font-bold py-2 px-4 rounded' %>
  </div>
</div>